import fs from "node:fs/promises";
import path from "node:path";
import { loadLocalCatalog } from "@/lib/local-catalog";

async function readOriginalBody() {
  const filePath = path.join(process.cwd(), "index.html");
  const html = await fs.readFile(filePath, "utf8");
  const match = html.match(/<body[^>]*>([\s\S]*)<\/body>/i);
  const body = match?.[1] ?? html;
  return body.replace(
    /<link rel="preload" as="script" fetchpriority="low" href="\/_next\/static\/chunks\/([^"?]+)(?:\?[^"]*)?">/g,
    '<link rel="preload" as="script" fetchpriority="low" href="/js/$1">'
  );
}

function escapeHtml(input: string) {
  return input
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function formatPrice(price: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 2,
  }).format(price);
}

function renderProductCard(product: Awaited<ReturnType<typeof loadLocalCatalog>>["products"][number]) {
  const salePrice =
    product.discount && product.discount > 0
      ? Math.max(0, product.price - Math.round((product.price * product.discount) / 100))
      : product.price;
  const stars = Array.from({ length: 5 }, (_, index) => index < Math.round(product.rating));
  const status = product.status ? product.status.charAt(0).toUpperCase() + product.status.slice(1) : "New";

  return `
    <article class="group rounded-[10px] border border-gray-200 bg-white overflow-hidden shadow-[0_1px_8px_rgba(15,23,42,0.04)] transition-all duration-300 hover:-translate-y-1 hover:shadow-xl">
      <div class="relative h-[330px] bg-white flex items-center justify-center overflow-hidden px-4 pt-4">
        <div class="absolute left-3 top-3 z-10 flex flex-col gap-2">
          <span class="inline-flex items-center px-3 py-1 rounded-lg text-xs font-semibold bg-gofarm-green text-white shadow">${escapeHtml(status)}</span>
          ${product.discount ? `<span class="inline-flex items-center px-3 py-1 rounded-lg text-xs font-semibold bg-red-500 text-white shadow">-${product.discount}%</span>` : ""}
        </div>
        <img
          src="${escapeHtml(product.imageSrc)}"
          alt="${escapeHtml(product.imageAlt)}"
          class="max-h-[240px] w-auto object-contain transition-transform duration-500 group-hover:scale-105 drop-shadow-[0_22px_22px_rgba(0,0,0,0.08)]"
          loading="lazy"
        >
      </div>
      <div class="px-4 pb-4 pt-2">
        <h4 class="text-[17px] font-bold text-gofarm-black leading-tight mb-1 line-clamp-1">${escapeHtml(product.name)}</h4>
        <div class="flex items-center gap-1 text-[12px] leading-none">
          ${stars.map((active) => `<span class="${active ? "text-yellow-400" : "text-gray-300"}">&#9733;</span>`).join("")}
          <span class="ml-1 text-gofarm-gray">(${product.reviews})</span>
        </div>
        <div class="flex items-end gap-2 mt-2 mb-4 flex-wrap">
          <span class="text-[22px] font-bold text-gofarm-green leading-none">${formatPrice(salePrice)}</span>
          ${product.discount ? `<span class="text-[18px] font-semibold text-gray-500 line-through leading-none">${formatPrice(product.price)}</span>` : ""}
          ${product.discount ? `<span class="inline-flex items-center rounded-md bg-red-50 px-2 py-0.5 text-xs font-medium text-red-500">-${product.discount}%</span>` : ""}
        </div>
        <button class="w-full inline-flex items-center justify-center gap-2 rounded-[8px] border border-gofarm-light-green/35 bg-white px-4 py-3 text-[15px] font-semibold text-gofarm-black transition-all duration-200 hover:border-gofarm-green hover:bg-gofarm-light-orange/10">
          <span>&#128722;</span>
          <span>Add to Cart</span>
        </button>
      </div>
    </article>
  `;
}

function buildFeaturedProductsSection(
  products: Awaited<ReturnType<typeof loadLocalCatalog>>["products"],
  categoryTitle: string
) {
  const visibleProducts = products.slice(0, 5);
  const totalProducts = Math.max(products.length, visibleProducts.length);

  return `
    <div><div class="max-w-(--breakpoint-xl) mx-auto px-4 flex flex-col lg:px-0 mt-16 lg:mt-24">
      <div class="text-center mb-8">
        <div class="inline-flex items-center gap-3 mb-4">
          <div class="h-1 w-12 bg-linear-to-r from-gofarm-light-green to-gofarm-green rounded-full"></div>
          <h2 class="text-3xl lg:text-4xl font-bold text-gofarm-black">Featured Products</h2>
          <div class="h-1 w-12 bg-linear-to-l from-gofarm-light-green to-gofarm-green rounded-full"></div>
        </div>
        <p class="text-gofarm-gray text-lg max-w-2xl mx-auto">Discover our carefully curated selection of premium products</p>
      </div>
      <div class="rounded-[28px] border border-gray-200 bg-white shadow-[0_18px_55px_rgba(15,23,42,0.08)] overflow-hidden">
        <div class="flex items-center justify-between gap-4 px-5 md:px-8 pt-6 pb-5 border-b border-gray-200">
          <div class="flex items-center gap-4">
            <h3 class="text-2xl font-extrabold tracking-tight text-gofarm-black">${escapeHtml(categoryTitle)}</h3>
            <span class="inline-flex items-center rounded-full bg-gofarm-light-orange/40 px-4 py-1.5 text-sm font-semibold text-gofarm-green">${totalProducts} Products</span>
          </div>
          <a href="/shop" class="inline-flex items-center gap-2 text-lg font-semibold text-gofarm-green hover:text-gofarm-light-green transition-colors">
            <span>View More</span>
            <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m9 18 6-6-6-6"></path></svg>
          </a>
        </div>
        <div class="relative px-5 md:px-8 py-6 md:py-8">
          <button type="button" aria-label="Previous products" class="absolute left-2 md:left-3 top-1/2 -translate-y-1/2 z-10 flex h-10 w-10 items-center justify-center rounded-full border border-gray-200 bg-white text-gray-400 shadow-sm transition-colors hover:border-gofarm-green hover:text-gofarm-green">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m15 18-6-6 6-6"></path></svg>
          </button>
          <div class="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-5">
            ${visibleProducts.map(renderProductCard).join("")}
          </div>
          <button type="button" aria-label="Next products" class="absolute right-2 md:right-3 top-1/2 -translate-y-1/2 z-10 flex h-10 w-10 items-center justify-center rounded-full border-2 border-gofarm-green bg-white text-gofarm-green shadow-md transition-colors hover:bg-gofarm-green hover:text-white">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m9 18 6-6-6-6"></path></svg>
          </button>
        </div>
        <div class="flex items-center justify-center gap-2 pb-6">
          <span class="h-2.5 w-8 rounded-full bg-gofarm-green"></span>
          <span class="h-2.5 w-2.5 rounded-full bg-gray-200"></span>
          <span class="h-2.5 w-2.5 rounded-full bg-gray-200"></span>
          <span class="h-2.5 w-2.5 rounded-full bg-gray-200"></span>
          <span class="h-2.5 w-2.5 rounded-full bg-gray-200"></span>
          <span class="h-2.5 w-2.5 rounded-full bg-gray-200"></span>
        </div>
      </div>
    </div></div>
  `;
}

export default async function HomePage() {
  const bodyHtml = await readOriginalBody();
  const catalog = await loadLocalCatalog();
  const products = catalog.products.slice(0, 13);
  const featuredCategoryTitle = catalog.categories.find((category) => category.count > 0)?.title ?? catalog.categories[0]?.title ?? "Vegetables";
  const sectionMarker = '<div><div class="max-w-(--breakpoint-xl) mx-auto px-4 flex flex-col lg:px-0 mt-16 lg:mt-24">';
  const featuredSection = buildFeaturedProductsSection(products, featuredCategoryTitle);

  const firstSectionStart = bodyHtml.indexOf(sectionMarker);
  const nextSectionStart = firstSectionStart >= 0 ? bodyHtml.indexOf(sectionMarker, firstSectionStart + sectionMarker.length) : -1;

  let transformedBody = bodyHtml;
  if (firstSectionStart >= 0 && nextSectionStart > firstSectionStart) {
    transformedBody =
      bodyHtml.slice(0, firstSectionStart) +
      featuredSection +
      bodyHtml.slice(nextSectionStart);
  }

  transformedBody = transformedBody.replace(/0 products/g, `${products.length} products`);

  return <div dangerouslySetInnerHTML={{ __html: transformedBody }} />;
}
